import{_ as a,E as r,c as t,J as o,a4 as l,o as i}from"./chunks/framework.OpyvxaCo.js";const m=JSON.parse('{"title":"赞助 RSSHub","description":"","frontmatter":{"sidebar":"auto"},"headers":[],"relativePath":"zh/sponsor.md","filePath":"zh/sponsor.md","lastUpdated":1711637073000}'),n={name:"zh/sponsor.md"},s=l('<h1 id="赞助-rsshub" tabindex="-1">赞助 RSSHub <a class="header-anchor" href="#赞助-rsshub" aria-label="Permalink to &quot;赞助 RSSHub&quot;">​</a></h1><p>RSSHub 是采用 MIT 许可的开源项目，使用完全免费。但是随着项目规模的增长，也需要有相应的资金支持才能持续项目的维护与开发.</p><p>你可以通过下列的方法来赞助 RSSHub 的开发.</p><h2 id="周期性赞助" tabindex="-1">周期性赞助 <a class="header-anchor" href="#周期性赞助" aria-label="Permalink to &quot;周期性赞助&quot;">​</a></h2><p>周期性赞助可以获得额外的回报，比如更快的 GitHub 响应或者你的名字会出现在 RSSHub 的 GitHub 仓库和现在我们的官网中.</p><ul><li>通过 <a href="https://github.com/sponsors/DIYgod" target="_blank" rel="noreferrer">GitHub</a> 赞助</li><li>通过 <a href="https://www.patreon.com/DIYgod" target="_blank" rel="noreferrer">Patreon</a> 赞助</li><li>通过 <a href="https://opencollective.com/RSSHub" target="_blank" rel="noreferrer">Open Collective</a> 赞助</li><li>通过 <a href="https://afdian.net/@diygod" target="_blank" rel="noreferrer">爱发电</a> 赞助</li><li>给我们发邮件联系赞助事宜: <a href="mailto:i@diygod.me" target="_blank" rel="noreferrer">i@diygod.me</a></li></ul><h2 id="一次性赞助" tabindex="-1">一次性赞助 <a class="header-anchor" href="#一次性赞助" aria-label="Permalink to &quot;一次性赞助&quot;">​</a></h2><p>我们通过以下方式接受赞助:</p><ul><li><a href="https://archive.diygod.me/images/wx.jpg" target="_blank" rel="noreferrer">微信支付</a></li><li><a href="https://archive.diygod.me/images/zfb.jpg" target="_blank" rel="noreferrer">支付宝</a></li><li><a href="https://www.paypal.me/DIYgod" target="_blank" rel="noreferrer">Paypal</a></li></ul><p>开源是一件非常昂贵的事情，没有这些个人和组织的帮助，RSSHub 是不可能存在和持续的。</p>',10);function p(h,d,c,_,b,u){const e=r("Sponsors");return i(),t("div",null,[s,o(e)])}const S=a(n,[["render",p]]);export{m as __pageData,S as default};
